231	common_chat_tool_choice common_chat_tool_choice_parse_oaicompat(const std::string & tool_choice) {
232	    if (tool_choice == "auto") {
233	        return COMMON_CHAT_TOOL_CHOICE_AUTO;
234	    }
235	    if (tool_choice == "none") {
236	        return COMMON_CHAT_TOOL_CHOICE_NONE;
237	    }
238	    if (tool_choice == "required") {
239	        return COMMON_CHAT_TOOL_CHOICE_REQUIRED;
240	    }
241	    throw std::invalid_argument("Invalid tool_choice: " + tool_choice);
242	}
