244	bool common_chat_templates_support_enable_thinking(const common_chat_templates * chat_templates) {
245	    common_chat_templates_inputs inputs;
246	    inputs.reasoning_format = COMMON_REASONING_FORMAT_DEEPSEEK;
247	    common_chat_msg msg;
248	    msg.role    = "user";
249	    msg.content = "test";
250	    inputs.messages = { msg };
251	    inputs.enable_thinking = true;
252	    inputs.add_generation_prompt = true;
253	    inputs.reasoning_format = COMMON_REASONING_FORMAT_DEEPSEEK;
254	
255	    auto params = common_chat_templates_apply(chat_templates, inputs);
256	    return params.supports_thinking;
257	}
