1885	common_chat_msg common_chat_peg_parse(const common_peg_arena &          src_parser,
1886	                                      const std::string &               input,
1887	                                      bool                              is_partial,
1888	                                      const common_chat_parser_params & params) {
1889	    const common_peg_arena & parser = src_parser.empty() ?
1890	        build_chat_peg_parser([](common_chat_peg_builder & p) { return p.content(p.rest()) + p.end(); }) :
1891	        src_parser;
1892	
1893	    if (src_parser.empty()) {
1894	        LOG_DBG("No parser definition detected, assuming pure content parser.");
1895	    }
1896	
1897	    const std::string effective_input = params.generation_prompt.empty()
1898	        ? input
1899	        : params.generation_prompt + input;
1900	
1901	    LOG_DBG("Parsing PEG input with format %s: %s\n", common_chat_format_name(params.format), effective_input.c_str());
1902	
1903	    common_peg_parse_flags flags = COMMON_PEG_PARSE_FLAG_LENIENT;
1904	    if (params.debug) {
1905	        flags |= COMMON_PEG_PARSE_FLAG_DEBUG;
1906	    }
1907	
1908	    common_peg_parse_context ctx(effective_input, flags);
1909	    auto result = parser.parse(ctx);
1910	
1911	    if (result.fail()) {
1912	        // During partial parsing, return partial results if any AST nodes were captured
1913	        // This allows streaming to work correctly for formats like FUNC_MARKDOWN_CODE_BLOCK
1914	        if (is_partial && result.end > 0) {
1915	            // Try to extract any partial results from what was successfully parsed
1916	            common_chat_msg msg;
1917	            msg.role = "assistant";
1918	            std::unique_ptr<common_chat_peg_mapper> mapper;
1919	            if (params.format == COMMON_CHAT_FORMAT_PEG_GEMMA4) {
1920	                mapper = std::make_unique<common_chat_peg_gemma4_mapper>(msg);
1921	            } else {
1922	                mapper = std::make_unique<common_chat_peg_mapper>(msg);
1923	            }
1924	            mapper->from_ast(ctx.ast, result);
1925	
1926	            if (ctx.is_debug()) {
1927	                fprintf(stderr, "\nAST for partial parse (fail):\n%s\n", ctx.ast.dump().c_str());
1928	                fflush(stderr);
1929	            }
1930	            return msg;
1931	        }
1932	        throw std::runtime_error(std::string("Failed to parse input at pos ") + std::to_string(result.end) + ": " +
1933	                                 effective_input.substr(result.end));

