1081	static common_chat_params common_chat_params_init_functionary_v3_2(const common_chat_template &    tmpl,
1082	                                                                   const autoparser::generation_params & inputs) {
1083	    common_chat_params data;
1084	
1085	    data.prompt           = common_chat_template_direct_apply_impl(tmpl, inputs);
1086	    data.format           = COMMON_CHAT_FORMAT_PEG_NATIVE;
